 3→use std::num::ParseIntError;
 4→
 5→use teloxide::types::{ChatId, MessageId, ThreadId};
 6→
 7→/// Parse a composite `to` address into `(ChatId, Option<ThreadId>)`.
 8→///
 9→/// Forum-topic sends encode the thread as `"chat_id:thread_id"`.
10→/// Plain sends are just `"chat_id"`.
11→pub(crate) fn parse_chat_target(to: &str) -> Result<(ChatId, Option<ThreadId>), ParseIntError> {
12→    if let Some((chat_part, thread_part)) = to.split_once(':') {
13→        let chat_id = ChatId(chat_part.parse::<i64>()?);
14→        let thread_id = Some(ThreadId(MessageId(thread_part.parse::<i32>()?)));
15→        Ok((chat_id, thread_id))
16→    } else {
17→        Ok((ChatId(to.parse::<i64>()?), None))
18→    }
19→}
