test("API endpoints work without auth on localhost", async ({ request }) => {
	// Protected endpoints should work without auth on localhost
	const resp = await request.get("/api/bootstrap");
	expect(resp.ok()).toBeTruthy();
});

test("sealed vault does not hide unencrypted session list", async ({ page }) => {
	const pageErrors = watchPageErrors(page);
	const session = {
		key: "main",
		label: "Main chat",
		preview: "hello",
		updatedAt: Date.now(),
		messageCount: 1,
	};

	await page.addInitScript((seedSession) => {
		const origFetch = window.fetch;
		window.fetch = function (...args) {
			var url = typeof args[0] === "string" ? args[0] : args[0].url;
			if (url.endsWith("/api/auth/status")) {
				return Promise.resolve(
					new Response(
						JSON.stringify({
							authenticated: true,
							setup_required: false,
							auth_disabled: false,
							localhost_only: true,
							has_password: false,
							has_passkeys: false,
							setup_complete: false,
						}),
						{
							status: 200,
							headers: { "Content-Type": "application/json" },
						},
					),
				);
			}
			return origFetch.apply(this, args);
		};

		Object.defineProperty(window, "__MOLTIS__", {
			configurable: true,
			set(value) {
				var next = value || {};
				next.vault_status = "sealed";
				next.sessions_recent = [seedSession];
				Object.defineProperty(window, "__MOLTIS__", {
					value: next,
					writable: true,
					configurable: true,
				});
			},
			get() {
				return undefined;
			},
		});
	}, session);

	await page.route("**/api/bootstrap*", async (route) => {
		await route.fulfill({
			status: 200,
			contentType: "application/json",
			body: JSON.stringify({
				channels: null,
				models: [],
				projects: [],
				sandbox: null,
				counts: null,
			}),
		});
	});
	await page.route("**/api/sessions*", async (route) => {
		await route.fulfill({
			status: 200,
			contentType: "application/json",
			body: JSON.stringify({
				sessions: [session],
				hasMore: false,
				nextCursor: null,
				total: 1,
			}),
		});
	});

	await page.goto("/chats/main");
	await expectPageContentMounted(page);
	await expect(page.getByText("Main chat", { exact: true })).toBeVisible();
	await expect(page.getByText("Vault is sealed", { exact: true })).toHaveCount(0);
	expect(pageErrors).toEqual([]);
});

